const response = $input.first().json;

// Extract text from OpenAI Responses API output
const output = response.output || [];
const messageBlock = output.find(o => o.type === 'message');
let footballNews = '';

if (messageBlock && messageBlock.content) {
  const textPart = messageBlock.content.find(c => c.type === 'output_text');
  if (textPart) {
    footballNews = textPart.text;
  }
}

if (!footballNews) {
  throw new Error('No football news returned from OpenAI');
}

const systemPrompt = [
  'You are a video content creator specializing in football/soccer content.',
  'Given the football news below, create a concise video generation prompt.',
  'Output ONLY valid JSON with these exact fields:',
  '"video_prompt": A visually descriptive prompt under 200 words for AI video generation.',
  'Include scene descriptions, mood, color palette, and camera movement suggestions.',
  '"image_search_queries": An array of 3 to 5 short search queries for relevant stock images.',
  '"title": A short, catchy video title.'
].join(' ');

return [{
  json: {
    openai_body: {
      model: 'gpt-4o',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: 'Create a video prompt from these trending football headlines:\n\n' + footballNews }
      ],
      temperature: 0.7,
      response_format: { type: 'json_object' }
    }
  }
}];

const response = $input.first().json;
const content = response.choices[0].message.content;

let parsed;
try {
  const jsonMatch = content.match(/```json?\s*([\s\S]*?)```/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[1].trim() : content.trim());
} catch (e) {
  parsed = {
    video_prompt: content || 'Dynamic football highlights montage with stadium atmosphere',
    image_search_queries: [
      'football match action shot',
      'football stadium aerial view',
      'football goal celebration'
    ],
    title: "Today's Football Highlights"
  };
}

const staticData = $getWorkflowStaticData('global');
staticData.video_prompt = parsed.video_prompt;
staticData.title = parsed.title;

return parsed.image_search_queries.map(query => ({
  json: { query }
}));

const items = $input.all();
const staticData = $getWorkflowStaticData('global');
const imageUrls = [];

for (const item of items) {
  const photos = item.json.photos || [];
  for (const photo of photos) {
    if (photo.src && photo.src.large) {
      imageUrls.push(photo.src.large);
    }
  }
}

return [{
  json: {
    video_prompt: staticData.video_prompt || '',
    title: staticData.title || 'Football Highlights',
    image_urls: imageUrls,
    primary_image: imageUrls[0] || ''
  }
}];
